// Filter sovereign states
const countries = Object.entries(manifest)
  .filter(([name]) => !excluded.has(name))
  .map(([name, filename]) => ({ name, filename }));

// Generate facts
const facts = countries.map(({ name, filename }) => {
  const slug = name
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')  // strip diacritics
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/_+$/, '')
    .replace(/^_+/, '');

  return {
    id: `flag_${slug}`,
    correctAnswer: name,
    acceptableAlternatives: acceptableAlternatives[name] || [],
    chainThemeId: regionMap[name] ?? 5,
    answerTypePoolId: 'country_names',
    difficulty: difficultyMap[name] ?? 3,
    funScore: funScoreMap[name] ?? 5,
    quizMode: 'image_question',
    imageAssetPath: `/assets/flags/${filename}`,
    quizQuestion: 'Which country does this flag belong to?',
    explanation: explanationMap[name] ?? `The flag of ${name}.`,
    visualDescription: visualDescMap[name] ?? `Flag of ${name}`,
    sourceName: 'Wikipedia',
    volatile: false,
    distractors: distractorMap[name] ?? [],
  };
});

